  1	import * as React from 'react';
  2	import _ from 'lodash';
  3	import classNames from 'classnames';
  4	import { useTranslation } from 'react-i18next';
  5	import { DomainPropType, DomainTuple } from 'victory-core';
  6	import {
  7	  Chart,
  8	  ChartAxis,
  9	  ChartAxisProps,
 10	  ChartBar,
 11	  ChartGroup,
 12	  ChartThemeColor,
 13	  ChartVoronoiContainer,
 14	} from '@patternfly/react-charts/victory';
 15	import { Alert, Card, CardBody, CardTitle } from '@patternfly/react-core';
 16	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 17	import { LoadingInline } from '../Loading';
 18	import {
 19	  formatDate,
 20	  getDropDownDate,
 21	  getXaxisValues,
 22	  hourformat,
 23	  monthYear,
 24	  parsePrometheusDuration,
 25	  timeToMinutes,
 26	} from '../pipelines-overview/dateTime';
 27	import { ALL_NAMESPACES_KEY } from '../../consts';
 28	import { getResultsSummary } from '../utils/summary-api';
 29	import { getFilter, useInterval } from '../pipelines-overview/utils';
 30	import { DataType, FLAGS, SummaryResponse } from '../../types';
 31	
 32	interface PipelinesAverageDurationProps {
 33	  timespan?: number;
 34	  domain?: DomainPropType;
 35	  bordered?: boolean;
 36	  interval?: number;
 37	  parentName?: string;
 38	  kind?: string;
 39	  namespace?: string;
 40	}
 41	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 42	
 43	const getChartData = (
 44	  tickValues: number[] | Date[],
 45	  data: SummaryResponse,
 46	  type: string,
 47	) => {
 48	  const chartData = tickValues?.map((value) => {
 49	    const s = data?.summary?.find((d) => {
 50	      const group_date = new Date(Number(d.group_value) * 1000);
 51	      if (type == 'hour') {
 52	        return group_date.getHours() === value;
 53	      }
 54	      if (type == 'day' || type == 'week') {
 55	        return group_date.toDateString() === new Date(value).toDateString();
 56	      }
 57	      if (type == 'month') {
 58	        return group_date.getMonth() === value.getMonth();
 59	      }
 60	    });
 61	    return {
 62	      x: value,
 63	      y: timeToMinutes(s?.avg_duration) || 0,
 64	    };
 65	  });
 66	  return chartData;
 67	};
 68	
 69	const PipelinesAverageDuration: React.FC<PipelinesAverageDurationProps> = ({
 70	  timespan,
 71	  domain,
 72	  bordered,
 73	  interval,
 74	  parentName,
 75	  namespace,
 76	  kind,
 77	}) => {
 78	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 79	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
 80	  const [data, setData] = React.useState<SummaryResponse>();
 81	  const [loaded, setLoaded] = React.useState(false);
 82	  const [pipelineAverageDurationError, setPipelineAverageDurationError] =
 83	    React.useState<string | undefined>();
 84	  const abortControllerRef = React.useRef<AbortController>();
 85	  const startTimespan = timespan - parsePrometheusDuration('1d');
 86	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
 87	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
 88	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
 89	  const domainValue: DomainPropType = {
 90	    x: domainX || [startDate, endDate],
 91	    y: domainY || undefined,
 92	  };
 93	
 94	  if (namespace == ALL_NAMESPACES_KEY) {
 95	    namespace = '-';
 96	  }
 97	
 98	  React.useEffect(() => {
 99	    return () => {
100	      abortControllerRef.current?.abort();
101	    };
102	  }, []);
103	
104	  React.useEffect(() => {
105	    setLoaded(false);
106	    setPipelineAverageDurationError(undefined);
107	    setData(undefined);
108	  }, [namespace, timespan]);
109	
110	  const [tickValues, type] = getXaxisValues(timespan);
111	
112	  const date = getDropDownDate(timespan).toISOString();
113	
114	  const getSummaryData = (group_by: string) => {
115	    abortControllerRef.current?.abort();
116	    abortControllerRef.current = new AbortController();
117	    setData(undefined);
118	    setPipelineAverageDurationError(undefined);
119	    setLoaded(false);
120	
121	    const summaryOpt = {
122	      summary: 'avg_duration',
123	      data_type: DataType.PipelineRun,
124	      filter: getFilter(date, parentName, kind),
125	      groupBy: group_by,
126	    };
127	
128	    getResultsSummary(
129	      namespace,
130	      summaryOpt,
131	      undefined,
132	      isDevConsoleProxyAvailable,
133	      abortControllerRef.current.signal,
134	      90000,
135	    )
136	      .then((d) => {
137	        setLoaded(true);
138	        setPipelineAverageDurationError(undefined);
139	        setData(d);
140	      })
141	      .catch((e) => {
142	        if (e.name === 'AbortError') {
143	          return;
144	        }
145	        setLoaded(true);
146	        setPipelineAverageDurationError(
147	          e.message || t('Failed to load average duration data'),
148	        );
149	        setData(undefined);
150	      });
151	  };
152	
153	  let xTickFormat;
154	  let dayLabel;
155	  let showLabel = false;
156	  let chartData = [];
157	  switch (type) {
158	    case 'hour':
159	      xTickFormat = (d) => hourformat(d);
160	      showLabel = true;
161	      domainValue.x = [0, 23];
162	      useInterval(() => getSummaryData('hour'), interval, namespace, date);
163	      dayLabel = formatDate(new Date());
164	      chartData = getChartData(tickValues, data, 'hour');
165	      break;
166	    case 'day':
167	      xTickFormat = (d) => formatDate(d);
168	      domainValue.x = [startDate, endDate];
169	      useInterval(() => getSummaryData('day'), interval, namespace, date);
170	      chartData = getChartData(tickValues, data, 'day');
171	      break;
172	    case 'week':
173	      xTickFormat = (d) => formatDate(d);
174	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
175	      useInterval(() => getSummaryData('week'), interval, namespace, date);
176	      chartData = getChartData(tickValues, data, 'week');
177	      break;
178	    case 'month':
179	      xTickFormat = (d) => monthYear(d);
180	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
181	      useInterval(() => getSummaryData('month'), interval, namespace, date);
182	      chartData = getChartData(tickValues, data, 'month');
183	      break;
184	    default:
185	      console.log('Received wrong data');
186	      break;
187	  }
188	
189	  const max = Math.max(...chartData.map((yVal) => yVal.y));
190	  const roundUp = (value, nearest) => {
191	    return Math.ceil(value / nearest) * nearest;
192	  };
193	  const nearest = max > 10 ? 10 : 5;
194	  const roundedMax = roundUp(max, nearest);
195	  domainValue.y =
196	    !isNaN(roundedMax) && roundedMax > 5 ? [0, roundedMax] : [0, 5];
197	
198	  if (!domainY) {
199	    let minY: number = _.minBy(chartData, 'y')?.y ?? 0;
200	    let maxY: number = _.maxBy(chartData, 'y')?.y ?? 0;
201	    if (minY === 0 && maxY === 0) {
202	      minY = -1;
203	      maxY = 1;
204	    } else if (minY > 0 && maxY > 0) {
205	      minY = 0;
206	    } else if (minY < 0 && maxY < 0) {
207	      maxY = 0;
208	    }
209	    domainValue.y = [minY, maxY];
210	  }
211	
212	  let xAxisStyle: ChartAxisProps['style'] = {
213	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
214	  };
215	  const yAxisStyle: ChartAxisProps['style'] = {
216	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
217	  };
218	  if (tickValues.length > 7) {
219	    xAxisStyle = {
220	      tickLabels: {
221	        fill: 'var(--pf-t--global--text--color--regular)',
222	        angle: 320,
223	        fontSize: 10,
224	        textAnchor: 'end',
225	        verticalAnchor: 'end',
226	      },
227	    };
228	  }
229	
230	  return (
231	    <>
232	      <Card
233	        className={classNames('pipeline-overview__number-of-plr-card', {
234	          'card-border': bordered,
235	        })}
236	      >
237	        <CardTitle className="pipeline-overview__number-of-plr-card__title">
238	          <span>{t('Average duration')}</span>
239	        </CardTitle>
240	        <CardBody className="pipeline-overview__number-of-plr-card__body">
241	          {pipelineAverageDurationError ? (
242	            <Alert
243	              variant="danger"
244	              isInline
245	              title={t('Unable to load average duration')}
246	              className="pf-v6-u-my-lg pf-v6-u-ml-lg"
247	            />
248	          ) : (
249	            <div className="pipeline-overview__number-of-plr-card__bar-chart-div">
250	              {loaded ? (
251	                <Chart
252	                  containerComponent={
253	                    <ChartVoronoiContainer
254	                      labels={({ datum }) => `${datum.y}m`}
255	                      constrainToVisibleArea
256	                    />
257	                  }
258	                  scale={{ x: 'time', y: 'linear' }}
259	                  domain={domainValue}
260	                  domainPadding={{ x: [30, 25] }}
261	                  height={145}
262	                  width={400}
263	                  padding={{
264	                    top: 10,
265	                    bottom: 55,
266	                    left: 50,
267	                  }}
268	                  themeColor={ChartThemeColor.blue}
269	                >
270	                  <ChartAxis
271	                    tickValues={tickValues}
272	                    style={xAxisStyle}
273	                    tickFormat={xTickFormat}
274	                    label={showLabel ? dayLabel : ''}
275	                  />
276	                  <ChartAxis
277	                    dependentAxis
278	                    style={yAxisStyle}
279	                    tickFormat={(v) => `${v}m`}
280	                  />
281	                  <ChartGroup>
282	                    <ChartBar data={chartData} barWidth={18} />
283	                  </ChartGroup>
284	                </Chart>
285	              ) : (
286	                <div className="pipeline-overview__number-of-plr-card__loading pf-v6-u-h-100">
287	                  <LoadingInline />
288	                </div>
289	              )}
290	            </div>
291	          )}
292	        </CardBody>
293	      </Card>
294	    </>
295	  );
296	};
297	
298	export default PipelinesAverageDuration;

