 54	        return group_date.toDateString() === new Date(value).toDateString();
 55	      }
 56	      if (type == 'month') {
 57	        return group_date.getMonth() === value.getMonth();
 58	      }
 59	    });
 60	    return {
 61	      x: value,
 62	      y: timeToMinutes(s?.avg_duration) || 0,
 63	    };
 64	  });
 65	  return chartData;
